Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &PedCod.IsEmpty() print printBlockFilterPedCod EndIf If not &PedSts.IsEmpty() &FilterPedStsValueDescription = &PedSts.EnumerationDescription()
print printBlockFilterPedSts EndIf If not &PedNovStsCod.IsEmpty() print printBlockFilterPedNovStsCod EndIf If not &PedCliCod.IsEmpty() print printBlockFilterPedCliCod EndIf If not &PedStsFin.IsEmpty() &FilterPedStsFinValueDescription = &PedStsFin.EnumerationDescription()
print printBlockFilterPedStsFin EndIf If not &PedNovStsFinCod.IsEmpty() print printBlockFilterPedNovStsFinCod EndIf If not &PedTraRedCod.IsEmpty() print printBlockFilterPedTraRedCod EndIf If not &PedDtaEms.IsEmpty() print printBlockFilterPedDtaEms EndIf If not &PedDtaEms_To.IsEmpty() &PedDtaEms_To_Description = format('%1 (%2)', "Emissão", "até") print printBlockFilterPedDtaEms_To EndIf If not &LctTip.IsEmpty() &FilterLctTipValueDescription = &LctTip.EnumerationDescription()
print printBlockFilterLctTip EndIf If not &LctAtuSal.IsEmpty() &FilterLctAtuSalValueDescription = &LctAtuSal.EnumerationDescription()
print printBlockFilterLctAtuSal EndIf If not &PedBlq.IsEmpty() &FilterPedBlqValueDescription = &PedBlq.EnumerationDescription()
print printBlockFilterPedBlq EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'LCTCOD' &LctCod1.FromString(&GridStateDynamicFilter.Value) If not &LctCod1.IsEmpty() &LctCod = &LctCod1 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector1 = !'PEDDTAFAT' &PedDtaFat1.FromString(&GridStateDynamicFilter.Value) &PedDtaFat_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaFat1.IsEmpty() &FilterPedDtaFatDescription = "Faturado" &PedDtaFat = &PedDtaFat1 print printBlockFilterPedDtaFat EndIf If not &PedDtaFat_To1.IsEmpty() &FilterPedDtaFatDescription = format('%1 (%2)', "Faturado", "até") &PedDtaFat = &PedDtaFat_To1 print printBlockFilterPedDtaFat EndIf Case &DynamicFiltersSelector1 = !'PEDVENCOD' &PedVenCod1.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod1.IsEmpty() &PedVenCod = &PedVenCod1 print printBlockFilterPedVenCod EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'LCTCOD' &LctCod2.FromString(&GridStateDynamicFilter.Value) If not &LctCod2.IsEmpty() &LctCod = &LctCod2 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector2 = !'PEDDTAFAT' &PedDtaFat2.FromString(&GridStateDynamicFilter.Value) &PedDtaFat_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaFat2.IsEmpty() &FilterPedDtaFatDescription = "Faturado" &PedDtaFat = &PedDtaFat2 print printBlockFilterPedDtaFat EndIf If not &PedDtaFat_To2.IsEmpty() &FilterPedDtaFatDescription = format('%1 (%2)', "Faturado", "até") &PedDtaFat = &PedDtaFat_To2 print printBlockFilterPedDtaFat EndIf Case &DynamicFiltersSelector2 = !'PEDVENCOD' &PedVenCod2.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod2.IsEmpty() &PedVenCod = &PedVenCod2 print printBlockFilterPedVenCod EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'LCTCOD' &LctCod3.FromString(&GridStateDynamicFilter.Value) If not &LctCod3.IsEmpty() &LctCod = &LctCod3 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector3 = !'PEDDTAFAT' &PedDtaFat3.FromString(&GridStateDynamicFilter.Value) &PedDtaFat_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaFat3.IsEmpty() &FilterPedDtaFatDescription = "Faturado" &PedDtaFat = &PedDtaFat3 print printBlockFilterPedDtaFat EndIf If not &PedDtaFat_To3.IsEmpty() &FilterPedDtaFatDescription = format('%1 (%2)', "Faturado", "até") &PedDtaFat = &PedDtaFat_To3 print printBlockFilterPedDtaFat EndIf Case &DynamicFiltersSelector3 = !'PEDVENCOD' &PedVenCod3.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod3.IsEmpty() &PedVenCod = &PedVenCod3 print printBlockFilterPedVenCod EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod (PedCod) when &OrderedBy = 1 order EmpCod FilCod PedCod when &OrderedBy = 2 order PedCod when &OrderedBy = 3 AND &OrderedDsc = False order (PedCod) when &OrderedBy = 3 AND &OrderedDsc = True order PedDtaEms when &OrderedBy = 4 AND &OrderedDsc = False order (PedDtaEms) when &OrderedBy = 4 AND &OrderedDsc = True order PedSts when &OrderedBy = 5 AND &OrderedDsc = False order (PedSts) when &OrderedBy = 5 AND &OrderedDsc = True order PedDtaPrv when &OrderedBy = 6 AND &OrderedDsc = False order (PedDtaPrv) when &OrderedBy = 6 AND &OrderedDsc = True order PedDtaFat when &OrderedBy = 7 AND &OrderedDsc = False order (PedDtaFat) when &OrderedBy = 7 AND &OrderedDsc = True order PedVlrBrt when &OrderedBy = 8 AND &OrderedDsc = False order (PedVlrBrt) when &OrderedBy = 8 AND &OrderedDsc = True order PedVlrLiq when &OrderedBy = 9 AND &OrderedDsc = False order (PedVlrLiq) when &OrderedBy = 9 AND &OrderedDsc = True order LctCod when &OrderedBy = 10 AND &OrderedDsc = False order (LctCod) when &OrderedBy = 10 AND &OrderedDsc = True
using DSwwPedidoFaturamento(&PedCod, &PedSts, &PedNovStsCod, &PedCliCod, &PedStsFin, &PedNovStsFinCod , &PedTraRedCod, &PedDtaEms, &PedDtaEms_To, &LctTip, &LctAtuSal, &PedBlq , &DynamicFiltersSelector1, &LctCod1, &PedDtaFat1, &PedDtaFat_To1, &PedVenCod1, &DynamicFiltersEnabled2 , &DynamicFiltersSelector2, &LctCod2, &PedDtaFat2, &PedDtaFat_To2, &PedVenCod2, &DynamicFiltersEnabled3 , &DynamicFiltersSelector3, &LctCod3, &PedDtaFat3, &PedDtaFat_To3, &PedVenCod3)
If PedSts = Status_Pedido.ABERTO RetornaPercentualEstoquePedido.Call(EmpCod, FilCod, PedCod, &BruMoeda, &ComEstMoeda, &SemEstMoeda, &ComEstTaxa)
Endif
&PedNovCliRaz = iif(PedCliCodRaz_Nov.Length() > 30, Substr(PedCliCodRaz_Nov,1,30)+'...', PedCliCodRaz_Nov) &NovoStatus = trim(PedNovStsNom) &NovoStatusFinanceiro = trim(PedNovStsFinNom) &AuxFin = UPPER(Substr(PedStsFin.EnumerationDescription(), 1,3)) &Redespacho = Substr(PedTraRedCodRaz, 1, 18)
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"wwPedidoFaturamentoGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"wwPedidoFaturamentoGridState")) Else &GridState.FromXml(&Session.Get(!"wwPedidoFaturamentoGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PEDCOD" &PedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTS" &PedSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDNOVSTSCOD" &PedNovStsCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCLICOD" &PedCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTSFIN" &PedStsFin.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDNOVSTSFINCOD" &PedNovStsFinCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDTRAREDCOD" &PedTraRedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDDTAEMS" &PedDtaEms.FromString(&GridStateFilterValue.Value) &PedDtaEms_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"LCTTIP" &LctTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"LCTATUSAL" &LctAtuSal.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDBLQ" &PedBlq.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
